#include<bits/stdc++.h>
using namespace std;
int a[501][501],b[501][501];
bool vis[501][501];
int n;
long long f()
{
	for(int i=1;i<=n;i++)
	{
		int cnt=0;
		for(int j=n;j>=1;j--)
		{
			cnt+=vis[i][j];
			if(!vis[i][j])
			{
				cnt=0;
			}
			b[i][j]=cnt;
		}
	}
	long long sum=0;
	for(int i=1;i<=n;i++)
	{
		for(int j=1;j<=n;j++)
		{
			int cnt=0,min1=b[i][j];
			while(vis[i+cnt][j])
			{
				sum+=min1;
				cnt++;
				min1=min(min1,b[i+cnt][j]);
			}
		}
	}
	return sum;
}
int main()
{
	scanf("%d",&n);
	for(int i=1;i<=n;i++)
	{
		for(int j=1;j<=n;j++)
		{
			scanf("%d",&a[i][j]);
			vis[i][j]=a[i][j]>=100;
		}
	}
	long long temp1=f();
	for(int i=1;i<=n;i++)
	{
		for(int j=1;j<=n;j++)
		{
			vis[i][j]=a[i][j]>100;
		}
	}
	long long temp2=f();
	printf("%lld",temp1-temp2);
	return 0;
}
